// ============================================================
// Script: gen-day01-vocab-extra.js
// Purpose: Expand Day 1 vocabulary.json from 600 to 1000+ words
// Run: node scripts/gen-day01-vocab-extra.js
// Author: 75 Days Hard English Course Team
// ============================================================

// Import required Node.js modules for file system operations
const fs = require('fs');
const path = require('path');

// ─────────────────────────────────────────────────────────────
// SECTION 1: Load existing vocabulary file
// ─────────────────────────────────────────────────────────────
// Read the current vocabulary JSON file
const vocabPath = path.join(__dirname, '../data/challenge/day-01/vocabulary.json');
const existing = JSON.parse(fs.readFileSync(vocabPath, 'utf8'));

// Get last ID from existing words to continue numbering
const lastId = existing.words[existing.words.length - 1].id; // Should be 600
console.log(`Existing words: ${existing.words.length}, last ID: ${lastId}`);

// ─────────────────────────────────────────────────────────────
// SECTION 2: Define 400+ new words across 15 new categories
// Each word follows the exact same detailed structure as existing words
// ─────────────────────────────────────────────────────────────

// Helper: create a full word object
function w(id, word, hindi, simpleMeaning, ipa, category, pos, cefr, syns, ants, daily, office, interview, business, formal, informal, usageNote, verbBase, verbS3, verbIng, verbPast, verbPP) {
  return {
    id,
    word,
    hindi,
    simpleMeaning,
    ipa,
    category,
    partOfSpeech: pos,
    cefrLevel: cefr,
    synonyms: syns,
    antonyms: ants,
    sentences: { daily, office, interview, business, formal, informal },
    usageNote: usageNote || null,
    verbForms: pos === 'verb' ? {
      base: verbBase || word,
      s3: verbS3 || word + 's',
      ing: verbIng || word + 'ing',
      past: verbPast || word + 'ed',
      pp: verbPP || word + 'ed'
    } : null
  };
}

// ─────────────────────────────────────────────────────────────
// CATEGORY 16: Numbers & Math Words (601–640)
