const healthWords = [
  w(861,'doctor','डॉक्टर / चिकित्सक','a person trained to treat illness and disease','/ˈdɒktər/','Health & Wellness','noun','A1',['physician','surgeon','specialist','medic'],['patient','nurse','student'],'See a doctor when you feel unwell — don\'t self-medicate.','Doctor\'s appointments in private hospitals require good English.','Doctor vocabulary: symptoms, prescription, diagnosis, treatment, medication.','Doctor-patient communication in English is a critical health skill.','The doctor is required to maintain confidentiality of patient information.','Bro, doctor said rest — but I\'m practicing English anyway!',"'Doctor' = medical professional. 'PhD Doctor' = academic/research doctor. 'Doctor' as verb (to doctor = to alter/falsify)."),
  w(862,'hospital','अस्पताल','a place where people go for medical treatment','/ˈhɒspɪtəl/','Health & Wellness','noun','A1',['clinic','medical center','infirmary'],['home','school','office'],'Hospital vocabulary: ward, patient, nurse, doctor, treatment.','Being admitted to hospital abroad requires English communication.','I want to speak English well enough to help in any hospital.','Hospital administration requires strong English documentation skills.','Hospitals are mandated to provide emergency care under law.','Emergency room, ICU, OPD, ward — hospital vocabulary matters!',"Hospital sections: OPD (out-patient), ICU (intensive care), emergency, ward (general room), operation theatre."),
  w(863,'medicine','दवाई / चिकित्सा विज्ञान','a substance used to treat illness; the science of treating illness','/ˈmedɪsɪn/','Health & Wellness','noun','A1',['drug','medication','treatment','remedy'],['poison','illness','disease'],'Take this medicine twice daily after meals.','Medicine labels are in English — knowing them is essential.','The medicine of failure is reflection + improvement. Always.','Pharmaceutical medicine development requires years of rigorous testing.','The prescription medicine must be dispensed by a licensed pharmacist.','Reading medicine labels correctly can save your life — learn it!',"'Medicine' = the drug (take your medicine) or the field (study medicine). 'Medication' = more formal/technical."),
  w(864,'exercise','व्यायाम','physical activity done to improve health','/ˈeksərsaɪz/','Health & Wellness','noun','A1',['workout','training','fitness','activity'],['rest','laziness','inactivity'],'Daily exercise + daily English practice = complete growth routine.','Exercise your mind with vocabulary and your body with walking.','English exercise: 50 translation questions every morning — done!','Employee exercise programs reduce sick days by 30% on average.','Regular aerobic exercise significantly reduces cardiovascular disease risk.','Exercise: done. English practice: done. You\'re unstoppable!',"'Exercise' (physical workout), 'exercise' (practice question in textbook). Both require effort and repetition.","exercise","exercises","exercising","exercised","exercised"),
  w(865,'pain','दर्द','a feeling of physical or emotional hurting','/peɪn/','Health & Wellness','noun','A1',['ache','hurt','discomfort'],['pleasure','comfort','relief'],'No pain, no gain — one of the most powerful English idioms.','Back pain from bad posture is a common office problem.','The pain of not knowing English is greater than studying pain.','Pain point = a problem that customers want solved. Key business term.','The extent of the pain and suffering was assessed by medical experts.','The real pain is not learning — that pain lasts forever!',"'Pain' (physical/emotional hurt). 'Pain point' (business: customer problem). 'No pain, no gain' (motivational). Know all three."),
  w(866,'symptom','लक्षण','a sign of an illness or condition','/ˈsɪmptəm/','Health & Wellness','noun','B1',['sign','indication','sign'],['cure','remedy','treatment'],'Common cold symptoms: runny nose, cough, fever, sore throat.','Describe your symptoms clearly to the doctor in English.','Symptom of poor English = fear of speaking. Cure = daily practice.','Customer pain points are the symptoms of a failing product.','The symptoms of the disease appeared within 72 hours of exposure.','Symptom check: confused about grammar? Time for more practice!',"Describing symptoms: 'I have a...' (headache/fever), 'I feel...' (dizzy/nauseous), 'My...hurts' (back/head)."),
  w(867,'prescription','नुस्खा / पर्चा','a written instruction from a doctor for medicine','/prɪˈskrɪpʃən/','Health & Wellness','noun','B1',['instruction','order','script'],['over-the-counter','self-medication'],'The prescription for English fluency: practice + consistency.','You need a prescription for these antibiotics — see a doctor.','Follow the prescription: study + practice + review. Daily. Always.','Prescription drug costs are covered under most health insurance policies.','Prescription medicines must be dispensed only by registered pharmacists.','My prescription: 1 hour English morning, 30 min evening, sleep 8 hours.',"'Prescription' (doctor\'s written instruction). 'OTC' = over-the-counter medicine (no prescription needed)."),
  w(868,'diet','आहार / खान-पान','the food you regularly eat; a special eating plan','/ˈdaɪət/','Health & Wellness','noun','A2',['nutrition','eating plan','food intake'],['overeating','fasting','junk'],'A healthy diet helps your brain learn English faster.','Are you on a special diet? I\'m vegetarian.','Diet for English: feed your mind vocabulary every day.','Corporate wellness programs now include diet counseling sessions.','The patient was placed on a strict low-sodium diet.','Diet + Exercise + Sleep + English = winning formula!',"'Diet' = what you normally eat OR a weight-loss plan. 'Balanced diet' = eating all food groups.","diet","diets","dieting","dieted","dieted"),
  w(869,'fitness','शारीरिक स्वास्थ्य / फिटनेस','being physically healthy and active','/ˈfɪtnəs/','Health & Wellness','noun','B1',['health','wellness','shape'],['sickness','lethargy','weakness'],'Mental fitness = English learning. Physical fitness = daily walk.','Corporate fitness programs improve employee performance significantly.','Fitness test for English: can you speak for 5 minutes straight?','Fitness apps and English apps — both equally important for growth.','Physical fitness is a prerequisite for certain defense and police roles.','Fitness + English = the two best investments in yourself!',"'Fitness' in health (physical fitness) and business ('fit for purpose', 'fitness for the role')."),
  w(870,'mental','मानसिक','relating to the mind','/ˈmentl/','Health & Wellness','adjective','B1',['psychological','cognitive','intellectual'],['physical','bodily','somatic'],'Mental health is as important as physical health — never ignore.','Mental Math: do it in your head without a calculator.','Mental strength: pushing through when English feels difficult.','Mental wellness programs in companies reduce burnout significantly.','Mental health is now recognized as a valid medical condition.','Bro, mental health day — rest, recharge, return stronger!',"'Mental' (of the mind): mental health, mental strength, mental note (remember something). All very common."),
  w(871,'nutrition','पोषण','the process of eating the right food for good health','/njuːˈtrɪʃən/','Health & Wellness','noun','B1',['nourishment','diet','food science'],['malnutrition','starvation','hunger'],'Good nutrition fuels your brain for maximum English learning.','Nutrition labels on food packages are written in English — learn to read them.','Think of vocabulary as nutrition for your brain.','Corporate nutrition programs improve focus and energy levels.','Nutrition guidelines are issued by the national health ministry.','Feed your brain nutrition = books. Feed your body = healthy food!',"'Nutrition' (science of food and health). 'Nutritious' (adjective: nutritious meal). 'Nutritionist' = expert in nutrition."),
  w(872,'stress','तनाव','mental or physical pressure causing discomfort','/stres/','Health & Wellness','noun','A2',['pressure','anxiety','tension'],['calm','relaxation','peace'],'Don\'t let exam stress stop you — channel it into preparation.','Workplace stress affects 85% of employees worldwide.','English stress = word stress (emphasis on syllables). Very different!','Stress management is the #1 soft skill employers look for.','Work-related stress is a recognized occupational health condition.','Stressed? Think of Day 75 — you speaking perfect English!',"'Stress' = mental pressure AND phonological stress (emphasizing a syllable). Both important in English.","stress","stresses","stressing","stressed","stressed"),
  w(873,'recovery','ठीक होना / पुनर्प्राप्ति','the process of getting better after illness or difficulty','/rɪˈkʌvəri/','Health & Wellness','noun','B1',['healing','rehabilitation','restoration'],['relapse','decline','deterioration'],'Recovery from failure = the most important skill in learning.','After illness, recovery requires rest, medicine, and patience.','English mistake recovery: acknowledge → correct → practice. Always.','Business recovery plans are essential after market downturns.','The patient\'s recovery was remarkably swift post-surgery.','You made a grammar mistake. Recovery plan: understand + rewrite.',"'Recovery' (health), 'business recovery' (economic rebound), 'data recovery' (tech). Very versatile word."),
  w(874,'healthy','स्वस्थ','in good health; good for you','/ˈhelθi/','Health & Wellness','adjective','A1',['fit','well','strong','nutritious'],['sick','unhealthy','ill'],'A healthy routine is the foundation of English learning success.','Healthy debates in office lead to better team decisions.','Healthy mind + healthy body = best possible learning results.','Healthy balance sheets attract investors and build stakeholder confidence.','A healthy diet reduces the risk of chronic disease by 40%.','Healthy habits: sleep 8h, exercise 30m, English 1h — daily!',"'Healthy' = good physical health, healthy food, healthy economy/relationship. All mean 'functioning well'."),
  w(875,'prevention','रोकथाम / बचाव','the act of stopping something bad from happening','/prɪˈvenʃən/','Health & Wellness','noun','B1',['protection','precaution','avoidance'],['cure','treatment','remedy'],'Prevention of English errors = learning rules before speaking.','Prevention is better than cure — one of the greatest English proverbs.','Grammar mistake prevention = understand the rule deeply.','Preventive healthcare reduces long-term medical costs significantly.','Prevention programs reduce workplace accidents by 60% on average.','Prevention > cure. Learn the grammar rule today, not after the mistake!',"'Prevention' (stopping before it happens). 'Cure' (fixing after it happened). 'Treatment' (ongoing management)."),
  w(876,'hygiene','स्वच्छता / सफाई','practices that keep you and your environment clean','/ˈhaɪdʒiːn/','Health & Wellness','noun','A2',['cleanliness','sanitation','health practices'],['dirt','filth','contamination'],'Good hygiene prevents illness — wash hands regularly.','Food hygiene standards are strictly regulated in all restaurants.','Mental hygiene: clear your mind before studying English.','Workplace hygiene is both a health requirement and productivity factor.','Hygiene protocols in food processing must meet ISO standards.','Digital hygiene: clean inbox, clear notes, organized study files!',"'Hygiene' = cleanliness practices. 'Dental hygiene' = teeth cleaning. 'Mental hygiene' = mental health habits."),
  w(877,'vaccine','टीका / वैक्सीन','a substance that protects against disease','/ˈvæksiːn/','Health & Wellness','noun','B1',['immunization','jab','injection'],['disease','infection','illness'],'COVID vaccines protected billions worldwide — remarkable science.','Vaccination drives require clear English communication to public.','Vaccine for bad grammar: understand the rule + 100 examples.','Pharmaceutical companies that produce vaccines have massive market value.','Mandatory vaccination policies were challenged in several courts.','Best vaccine: knowledge. Best cure: education. Study English daily!',"'Vaccine' (the substance). 'Vaccination' (the process of giving vaccine). 'Immunity' (the protection gained)."),
  w(878,'insurance','बीमा','an arrangement to compensate for loss or illness','/ɪnˈʃʊərəns/','Health & Wellness','noun','A2',['coverage','protection','policy'],['risk','unprotected','exposed'],'Health insurance is essential for everyone today.','Employment benefits often include health insurance coverage.','Investing in English is my best insurance for career success.','Health insurance penetration in India is growing rapidly post-COVID.','The insurance policy clearly states the terms and conditions.','Bro, check your health insurance policy — do you have coverage?',"'Insurance' types: health, life, vehicle, property, travel. 'Premium' = the monthly payment. 'Claim' = requesting payment."),
  w(879,'ambulance','एम्बुलेंस','a vehicle for taking sick people to hospital quickly','/ˈæmbjuːləns/','Health & Wellness','noun','A2',['emergency vehicle','rescue vehicle'],['taxi','bus','car'],'Call an ambulance immediately if someone collapses.','In an emergency: "Call an ambulance! Someone needs urgent help!"','Key English phrase: "I need an ambulance at [location]."','Ambulance response time directly impacts patient survival rates.','The ambulance service provider was liable for delayed response.','Emergency number: 112 in India. Always say your location clearly!',"Emergency phrases: 'Call an ambulance!', 'I need help!', 'Please hurry!', 'The address is...' — know them!"),
  w(880,'pharmacy','दवाखाना / फार्मेसी','a shop where medicines are sold','/ˈfɑːrməsi/','Health & Wellness','noun','A2',['drugstore','chemist','dispensary'],['hospital','clinic','doctor'],'Get this medicine from the pharmacy — bring the prescription.','Pharmacy vocabulary: counter, prescription, over-the-counter, generic.','Pharmacy chains like Apollo Pharmacy use English for all labels.','Pharmaceutical companies contribute significantly to national healthcare.','Pharmacies are regulated by the Drug Controller General of India.','Bro, pharmacy pe jaana tha — forgot the medicine name again!',"'Pharmacy' = the shop. 'Pharmacist' = the professional. 'Pharmaceutical' = relating to drugs/medicine."),
];

