const businessWords = [
  w(921,'business','व्यापार / कारोबार','the activity of buying and selling goods or services','/ˈbɪznɪs/','Business & Finance','noun','A1',['trade','commerce','enterprise'],['hobby','leisure','non-profit'],'English is the language of international business — learn it.','Business communication requires formal, clear, and professional English.','My business goal: use English to connect with global clients.','Business English is different from daily spoken English — both matter.','The business dispute was referred to commercial arbitration.','Mind your own business — English idiom: don\'t interfere!',"'Business' as noun (I run a business), adjective (business meeting), and idiom ('none of your business')."),
  w(922,'profit','मुनाफ़ा / लाभ','the money made after all costs are paid','/ˈprɒfɪt/','Business & Finance','noun','A2',['gain','surplus','income','return'],['loss','deficit','expense'],'Learning English is an investment with guaranteed profit.','Profit = Revenue - Cost. Basic business formula everyone needs.','My English investment profit: better job, higher salary, global network.','Profit margins in IT services hover around 20-25% typically.','Profits earned were distributed to shareholders as dividends.','No pain, no gain... no study, no profit. Simple truth!',"'Profit' (money made). 'Profit margin' = (profit/revenue × 100). 'Non-profit' = organization not for profit."),
  w(923,'invest','निवेश करना','to put money or time into something to get profit later','/ɪnˈvest/','Business & Finance','verb','A2',['fund','finance','support','contribute'],['waste','spend recklessly','lose'],'Invest 1 hour in English daily — ROI is career transformation.','The best investment you can make is in yourself.','I invested 3 months in this English course — worth every minute.','Investing in employee training yields long-term business returns.','Investors are required to disclose all material holdings annually.','Invest in English now — dividend paid for your entire life!',"'Invest' (money/time for future return). 'Investor' = person who invests. 'Investment' = amount invested.","invest","invests","investing","invested","invested"),
  w(924,'budget','बजट','a plan for how to spend money','/ˈbʌdʒɪt/','Business & Finance','noun','A2',['plan','allocation','funds','estimate'],['overspend','debt','waste'],'Budget your English study time like you budget money — wisely.','We\'re over budget on this project — need to cut costs.','My time budget: 30% study, 30% practice, 30% review, 10% rest.','Annual budget planning is the most critical corporate finance exercise.','The budget proposal must be approved by the board of directors.','On budget, on time — the holy grail of project management!',"'Budget' (noun: the total amount), 'budget' (verb: I need to budget), 'budget' (adjective: budget hotel = cheap).","budget","budgets","budgeting","budgeted","budgeted"),
  w(925,'revenue','राजस्व / आमदनी','the total income earned by a company','/ˈrevənjuː/','Business & Finance','noun','B1',['income','earnings','turnover'],['expense','cost','loss'],'Revenue = all money coming in before deductions.','Our company\'s annual revenue grew by 40% last year.','Knowledge of revenue metrics impresses interviewers in business roles.','Revenue diversification reduces risk in volatile market conditions.','Revenue from operations must be reported separately in financial statements.','Revenue vs. profit: Revenue is total income; profit is what\'s left!',"'Revenue' (total income), 'net revenue' (after deductions), 'revenue stream' (source of income). Key finance terms."),
  w(926,'expense','खर्च / व्यय','money spent on something; a cost','/ɪkˈspens/','Business & Finance','noun','A2',['cost','expenditure','outgoing'],['income','profit','revenue'],'English course expense: ₹0 if you use free resources wisely.','All expenses must be submitted with receipts by month-end.','Time is your only expense in this English learning course.','Expense management systems track all corporate spending in real-time.','Unreasonable expenses claimed on business accounts can lead to audit.','Biggest expense? Time. Make every minute of study count!',"'Expense' (one cost), 'expenses' (many costs), 'at the expense of' = sacrificing something else for gain."),
  w(927,'loan','ऋण / क़र्ज़','money borrowed that must be paid back, usually with interest','/loʊn/','Business & Finance','noun','A2',['debt','credit','borrowing'],['savings','investment','gift'],'Take a loan of time from your hobbies — invest in English.','Student loans help many access higher education opportunities.','No financial loan needed for English — only time investment.','Business loans are available from banks at competitive interest rates.','Loan agreements must be signed by both parties before disbursement.','Bro, free English learning — no loan required!',"'Loan' (money borrowed). 'Lend' (to give temporarily). 'Borrow' (to take temporarily). Don\'t confuse borrow/lend!"),
  w(928,'tax','कर / टैक्स','money paid to the government on income and purchases','/tæks/','Business & Finance','noun','A2',['duty','levy','tariff'],['subsidy','exemption','deduction'],'Knowledge of English taxation terms is valuable for finance professionals.','GST, income tax, TDS — all English terms you need to know.','English is taxed only one way: with time. Pay it willingly.','Corporate tax optimization requires deep legal and financial knowledge.','Tax evasion is a criminal offense under the Income Tax Act.','The only two certainties in life: death and taxes — English proverb!',"'Tax' types: income tax, VAT/GST, corporate tax, property tax, capital gains tax. All important in finance."),
  w(929,'contract','अनुबंध / अनुबंधित','a legal agreement between parties; to decrease in size','/ˈkɒntrækt/','Business & Finance','noun','B1',['agreement','deal','pact'],['dispute','verbal','handshake'],'Read every contract carefully before signing — English skill saves money!','The job contract specifies salary, role, and terms clearly.','A contract with English fluency: daily practice for daily progress.','Contracts must contain offer, acceptance, consideration, and intention.','The employment contract was upheld by the labor court tribunal.','Sign the contract — but read every clause first!',"'Contract' (noun = agreement) and 'contract' (verb = to get smaller: the market contracted). Two meanings.","contract","contracts","contracting","contracted","contracted"),
  w(930,'negotiate','बातचीत करना / मोलभाव करना','to discuss something to reach an agreement','/nɪˈɡoʊʃieɪt/','Business & Finance','verb','B1',['discuss','bargain','mediate'],['demand','refuse','force'],'Negotiate your salary with confidence in English.','Use "I would like to discuss..." as a polite negotiation opener.','Negotiate → the English skill that can literally change your income.','Effective negotiation skills increase business deal closure rates.','Parties may negotiate terms of the settlement before arbitration.','Negotiate like a pro: listen first, then speak — always!',"'Negotiate' the salary/deal. 'Negotiation' = the process. 'Negotiator' = the person. 'Non-negotiable' = cannot be changed.","negotiate","negotiates","negotiating","negotiated","negotiated"),
  w(931,'invoice','चालान / इनवॉइस','a document listing goods and their prices for payment','/ˈɪnvɔɪs/','Business & Finance','noun','B1',['bill','receipt','statement'],['payment','refund','cash'],'Send the invoice with all required details by email.','Invoice vocabulary: amount due, payment terms, GST, due date.','Every freelance English teacher uses invoices — learn this vocabulary.','Timely invoice submission ensures smooth cash flow for businesses.','The invoice must be issued within 30 days of service delivery.','Invoice sent — now politely follow up if not paid in 30 days!',"'Invoice' (request for payment), 'receipt' (proof of payment), 'bill' (informal invoice). All related but different.","invoice","invoices","invoicing","invoiced","invoiced"),
  w(932,'interest','ब्याज / रुचि','extra money paid for a loan; curiosity about something','/ˈɪntrəst/','Business & Finance','noun','A2',['curiosity','attention','rate'],['boredom','disinterest','principal'],'Learn English with genuine interest — that\'s the secret.','Interest rate on loans varies between banks — compare carefully.','My interest in English grows every day — unstoppable now.','Rising interest rates affect business loan repayment capacity.','Interest earned on savings accounts is subject to income tax.','Interest rate hike? Save more, spend less. Simple economics!',"'Interest' (curiosity), 'interest' (finance: money for borrowing), 'in the interest of' = for the benefit of."),
  w(933,'profit margin','लाभ मार्जिन','the percentage of revenue that becomes profit','/ˈprɒfɪt ˈmɑːrdʒɪn/','Business & Finance','noun','B2',['margin','return','profit ratio'],['loss','deficit','write-off'],'High profit margin = business efficiency and pricing power.','Understanding profit margin impresses finance interviewers.','My profit margin from English: career growth + salary hike + confidence.','Gross margin vs. net margin — know both for business discussions.','The company maintained a 35% profit margin despite market challenges.','Profit margin = (Profit ÷ Revenue) × 100. Remember this!',"'Gross margin' = before overhead. 'Net margin' = after all expenses. 'Operating margin' = from core business."),
  w(934,'shareholder','शेयरधारक','a person who owns shares in a company','/ˈʃeərhoʊldər/','Business & Finance','noun','B1',['stockholder','investor','owner'],['debtor','borrower','employee'],'Shareholders vote on major company decisions.','Shareholder value is created through profit, growth, and dividends.','Become a shareholder of your English journey — own your progress.','Shareholder meetings (AGMs) are annual mandatory corporate events.','Shareholders are entitled to annual reports and dividend declarations.','Own your learning — be a shareholder in your own success!',"'Shareholder' = owns equity. 'Stakeholder' = anyone affected by the business (wider group). Common business distinction."),
  w(935,'dividend','लाभांश','a share of profits paid to shareholders','/ˈdɪvɪdend/','Business & Finance','noun','B2',['return','payout','bonus'],['loss','debt','withholding'],'The dividend of learning English: a lifetime of opportunity.','Consistent dividends signal a company\'s financial health and stability.','English fluency pays dividends throughout your entire career.','Dividend payouts are subject to dividend distribution tax in India.','The interim dividend was declared at the board meeting.','English is the dividend-paying stock of your personal portfolio!',"'Dividend yield' = dividend/stock price × 100. 'Ex-dividend date' = last date to qualify for dividend."),
  w(936,'currency','मुद्रा','the money used in a country','/ˈkɜːrənsi/','Business & Finance','noun','B1',['money','cash','legal tender'],['barter','credit','crypto'],'The currency of the future: English skills and digital literacy.','Exchange rates determine currency value in international trade.','English is the global currency of communication — invest now.','Currency fluctuations affect international business costs and revenues.','The currency must be declared at customs if above the permitted limit.','English = the universal currency. Accepted everywhere!',"Major currencies: USD (Dollar), EUR (Euro), GBP (Pound), INR (Rupee), JPY (Yen). Know them for business."),
  w(937,'market','बाज़ार / मार्केट','a place where things are bought and sold; the total demand','/ˈmɑːrkɪt/','Business & Finance','noun','A1',['marketplace','bazaar','economy'],['private','exclusive','closed'],'The job market demands English fluency in almost every sector.','Target market = the specific group of customers for your product.','English opens doors in every market — local and global.','Market research is essential before launching any new product.','Market manipulation is a serious offense under securities law.','Market leader, market share, market research — learn these terms!',"'Market' types: stock market, job market, local market, global market, niche market. All very common.","market","markets","marketing","marketed","marketed"),
  w(938,'startup','स्टार्टअप','a new business, especially tech-focused','/ˈstɑːrtʌp/','Business & Finance','noun','B1',['new company','venture','enterprise'],['corporation','established company','MNC'],'India is the third-largest startup ecosystem globally after US and China.','Startup English is casual but professional — know both modes.','This course is my personal startup — building fluency from scratch.','Startups disrupt traditional industries with innovative solutions.','Startup funding rounds: pre-seed, seed, Series A, B, C, IPO.','Startup vibes: hustle, learn, grow, repeat — just like English!',"'Startup' (new company), 'startup ecosystem' (network of startups), 'unicorn' = startup valued at $1 billion+."),
  w(939,'entrepreneur','उद्यमी / कारोबारी','a person who starts and runs their own business','/ˌɒntrəprəˈnɜːr/','Business & Finance','noun','B1',['founder','business person','innovator'],['employee','worker','follower'],'English-speaking entrepreneurs have access to global investors.','Think like an entrepreneur: problems are opportunities.','My entrepreneurial venture: English fluency in 75 days!','Entrepreneurship drives innovation, job creation, and economic growth.','Entrepreneurs must comply with all relevant company and tax laws.','Entrepreneur mindset: fail fast, learn faster, grow fastest!',"'Entrepreneur' (French origin, challenging pronunciation). Practice: ON-truh-pruh-NUR. Worth mastering!"),
  w(940,'investment','निवेश','putting money, time, or effort into something for future gain','/ɪnˈvestmənt/','Business & Finance','noun','A2',['expenditure','funding','capital'],['waste','loss','expense'],'The best investment: English skills. ROI = career for life.','Investment in self-development pays the highest returns.','Time invested in English = compounding returns over a lifetime.','Foreign direct investment drives economic growth in developing countries.','Investment decisions must be based on proper due diligence.','Calculate your English ROI: 1 hour/day × 75 days = fluency!',"'Investment' (financial: put money), 'investment' (time/effort). 'Return on Investment (ROI)' = what you get back."),
];

